String routeLocation(AppRoutePath route) => route.location;

String _routePath(
  List<String> segments, {
  Map<String, String>? queryParameters,
}) {
  final query = queryParameters?.isEmpty ?? true ? null : queryParameters;
  final text = Uri(pathSegments: segments, queryParameters: query).toString();
  if (text.isEmpty) return '/';
  return text.startsWith('/') ? text : '/$text';
}

bool routeRequiresAuth(AppRoutePath route) => route.requiresAuth;

List<Object> routeGuards(
  AppRoutePath route,
  $AppRouter router,
) {
  return switch (route) {
    _ => const [],
  };
}

extension AppRouterContext on BuildContext {
  RouterController<AppRoutePath> get _routerController =>
      RouterController.of<AppRoutePath>(this);
  AppRoutesNavigator get navigator => AppRoutesNavigator(_routerController);
}

final class AppRoutesNavigator {
  const AppRoutesNavigator(this._router);

  final RouterController<AppRoutePath> _router;

  RouteAction<void> notFound({String path = ''}) =>
      RouteAction(_router, NotFoundRoute(path: path));

  RouteAction<void> route0() => RouteAction(_router, Route0Route());

  RouteAction<void> route1() => RouteAction(_router, Route1Route());

  RouteAction<void> route10() => RouteAction(_router, Route10Route());

  RouteAction<void> route100() => RouteAction(_router, Route100Route());

  RouteAction<void> route101() => RouteAction(_router, Route101Route());

  RouteAction<void> route102() => RouteAction(_router, Route102Route());

  RouteAction<void> route103() => RouteAction(_router, Route103Route());

  RouteAction<void> route104() => RouteAction(_router, Route104Route());

  RouteAction<void> route105() => RouteAction(_router, Route105Route());

