AppRoutePath parseAppRoute(Uri uri) {
  final segments = uri.pathSegments;

  if (segments.length == 1 && segments[0] == '404') {
    return NotFoundRoute(path: uri.queryParameters['path'] ?? '');
  }
  if (segments.length == 2 && segments[0] == 'section' && segments[1] == '0') {
    return const Route0Route();
  }
  if (segments.length == 2 && segments[0] == 'section' && segments[1] == '1') {
    return const Route1Route();
