AppRoutePath _notFoundRoute(Uri uri) => NotFoundRoute(path: uri.toString());

bool? _parseBool(String? value) {
  return switch (value) {
    'true' || '1' => true,
    'false' || '0' => false,
    null || '' => null,
    _ => null,
  };
}

